),
matched AS (
  SELECT DISTINCT m.id FROM matches m
  JOIN teams h ON h.id = m.home_team_id
  JOIN teams a ON a.id = m.away_team_id
  JOIN fd f ON f.kickoff_at::timestamptz = m.kickoff_at AND f.home_code = h.code AND f.away_code = a.code
)
DELETE FROM matches WHERE phase='group' AND id NOT IN (SELECT id FROM matched);